INSERT INTO public.knowledge_base (title, content, category, data_type) VALUES
('عن Sity Cloud', 'Sity Cloud هي منصة SaaS متكاملة تتيح لأي شخص أو شركة إنشاء وإدارة موقع إلكتروني احترافي بسهولة تامة، بدون الحاجة إلى خبرة برمجية. النظام مبني على Plugins وThemes مرنة، مما يتيح تخصيص كامل حسب نوع النشاط.', 'عام', 'text'),
('خدمات المنصة', 'المنصة توفر Page Builder متطور يعمل بنظام Sections وWidgets لبناء الصفحات بشكل بصري. تدعم تركيب Plugins جاهزة تضيف وظائف متقدمة مثل: المتاجر الإلكترونية (E-commerce)، أنظمة الحجز (Booking Systems)، إدارة المحتوى (CMS/Blog)، التحليلات (Analytics)، أدوات التسويق (Marketing Tools).', 'خدمات', 'text'),
('الذكاء الاصطناعي في Sity Cloud', 'واحدة من أهم نقاط القوة في Sity Cloud هي دمج الذكاء الاصطناعي داخل النظام. المساعد الذكي قادر على: إنشاء صفحات كاملة تلقائياً، كتابة مقالات ومحتوى احترافي، تحسين محركات البحث (SEO)، اقتراح تصميمات وتجارب مستخدم، تنفيذ مهام شبه تلقائية نيابة عن المستخدم.', 'تقنية', 'text'),
('Sity Expert - منصة الفريلانس', 'Sity Expert هي منصة Freelance متخصصة عبر expert.sity.cloud تربط بين أصحاب المشاريع والمحترفين في مجالات: تطوير المواقع، التصميم، التسويق الرقمي، كتابة المحتوى، إدارة المتاجر الإلكترونية. توفر نظام عرض خدمات، نظام طلبات، تقييمات وسمعة، إدارة كاملة للتعاملات.', 'خدمات', 'text'),
('البرامج التدريبية', 'نقدم من خلال Sity Expert برامج تدريبية تشمل: كورسات مجانية ومدفوعة، منح تدريبية لتأهيل المبتدئين، مسارات تعليمية احترافية تؤهل لسوق العمل، دعم مباشر للمتدربين وربطهم بفرص عمل داخل المنصة.', 'تدريب', 'text'),
('رؤية الشركة', 'نحن لا نقدم مجرد أدوات، بل نبني Ecosystem متكامل يساعد: رواد الأعمال على إطلاق مشاريعهم، الشركات على التوسع الرقمي، الأفراد على اكتساب مهارات وتحقيق دخل. المنصة نظام تشغيل متكامل لإدارة المشاريع الرقمية.', 'عام', 'text'),
('نظام الواتساب بوت', 'نظام ذكي يعتمد على فهم المستخدم وتحليل طلبه بدقة وليس مجرد ردود تلقائية. البوت يستقبل استفسار العميل ويحلله، يحدد احتياجاته، يطرح أسئلة توضيحية، يقدم اقتراحات مناسبة، يشرح الخدمات تدريجياً، يتعامل بأسلوب بشري احترافي لبناء الثقة.', 'تقنية', 'text'),
('أنواع المواقع المدعومة', 'يمكن إنشاء أي نوع من المواقع: Portfolio، متجر إلكتروني، مدونة، موقع خدمات، نظام حجوزات، موقع شركة، موقع تعليمي، أو أي فكرة أخرى يحتاجها العميل.', 'خدمات', 'text');
